// ✅ UPDATED: src/pages/TaxiDetailsScreen.js
// (More greener section headers + smaller right-side values + “:” everywhere + Statut chip)

import React, { useMemo } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Pressable,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";
import { useTranslation } from "../i18n";

export default function TaxiDetailsScreen() {
  const navigation = useNavigation();
  const { t, lang } = useTranslation();

  // ✅ Dummy data for now (same format you gave)
  const data = useMemo(
    () => ({
      status: lang === "fr" ? "VÉHICULE AUTORISÉ" : "AUTHORIZED VEHICLE",
      plate: "CE 458-Y",

      registration: {
        title:
          lang === "fr"
            ? "Identification du véhicule"
            : "Vehicle identification",
        subtitle: lang === "fr" ? "(Carte grise)" : "(Registration)",
        rows: [
          {
            icon: "🚗",
            label: lang === "fr" ? "Immatriculation" : "Plate number",
            value: "CE 458-Y",
          },
          {
            icon: "🚕",
            label: lang === "fr" ? "Marque & Modèle" : "Brand & model",
            value: "Toyota Yaris (Sedan)",
          },
          {
            icon: "📍",
            label: lang === "fr" ? "Propriétaire" : "Owner",
            value: "NGOUMOU Jean-Pierre",
          },
        ],
      },

      licence: {
        title:
          lang === "fr"
            ? "Autorisation d'exercer"
            : "Operating authorization",
        subtitle: lang === "fr" ? "(Licence)" : "(Licence)",
        rows: [
          {
            icon: "🚗",
            label: lang === "fr" ? "Numéro de licence" : "Licence number",
            value: "CUY-2026-TX-8842",
          },
          {
            icon: "🕒",
            label: lang === "fr" ? "Validité" : "Validity",
            value:
              lang === "fr"
                ? "01/01/2026 au 31/12/2026"
                : "01/01/2026 to 31/12/2026",
          },
          {
            icon: "📍",
            label: lang === "fr" ? "Zone" : "Zone",
            value: lang === "fr" ? "Yaoundé Urbain" : "Yaoundé Urban",
          },
          {
            icon: "🚕",
            label: lang === "fr" ? "Numéro de portière" : "Door number",
            value: "1055-B",
          },
        ],
      },

      driver: {
        title:
          lang === "fr" ? "Profil du chauffeur" : "Driver profile",
        subtitle: lang === "fr" ? "(Permis & CNI)" : "(Permit & ID)",
        initials: "FM",
        fullName: "FOUDA MEKONGO Christian",
        rows: [
          {
            icon: "🚗",
            label: lang === "fr" ? "Numéro permis" : "Permit number",
            value: "04/1055/B/2018",
          },
          {
            icon: "🅱️",
            label: lang === "fr" ? "Catégorie" : "Category",
            value: "B",
          },
          {
            icon: "🪪",
            label: lang === "fr" ? "Numéro CNI" : "ID number",
            value: "112455987",
          },
        ],
      },

      insurance: {
        title:
          lang === "fr" ? "Couverture risques" : "Risk coverage",
        subtitle: lang === "fr" ? "(Assurance)" : "(Insurance)",
        rows: [
          {
            icon: "🚗",
            label: lang === "fr" ? "Compagnie" : "Company",
            value: "ACTIVA Assurance",
          },
          {
            icon: "🕒",
            label: lang === "fr" ? "Expiration" : "Expiration",
            value: "15/06/2026",
          },
          // ✅ requested: Statut : [VALIDE]
          {
            icon: "✅",
            label: lang === "fr" ? "Statut" : "Status",
            value: "VALIDE",
            isStatus: true,
          },
        ],
      },
    }),
    [lang]
  );

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
      >
        {/* ===== Top row (Back) ===== */}
        <View style={styles.topRow}>
          <Pressable style={styles.backBtn} onPress={() => navigation.goBack()}>
            <Text style={styles.backIcon}>‹</Text>
            <Text style={styles.backText}>{t("common.back") ?? "Back"}</Text>
          </Pressable>
        </View>

        {/* ===== Status banner ===== */}
        <View style={styles.bannerWrap}>
          <View style={styles.banner}>
            <View style={styles.bannerDot} />
            <Text style={styles.bannerText}>{data.status}</Text>
          </View>
        </View>

        {/* ===== Plate big ===== */}
        <View style={styles.plateWrap}>
          <View style={styles.plateBox}>
            <Text style={styles.plateText}>{data.plate}</Text>
          </View>
        </View>

        {/* ===== Cards ===== */}
        <SectionCard
          icon="🚕"
          title={data.registration.title}
          subtitle={data.registration.subtitle}
          rows={data.registration.rows}
        />

        <SectionCard
          icon="✅"
          title={data.licence.title}
          subtitle={data.licence.subtitle}
          rows={data.licence.rows}
          headerVariant="green"
        />

        <SectionCard
          icon="🧑🏾‍✈️"
          title={data.driver.title}
          subtitle={data.driver.subtitle}
          rows={data.driver.rows}
          headerVariant="green"
          topLeftAvatar={{ initials: data.driver.initials, name: data.driver.fullName }}
        />

        <SectionCard
          icon="✅"
          title={data.insurance.title}
          subtitle={data.insurance.subtitle}
          rows={data.insurance.rows}
          headerVariant="green"
        />
      </ScrollView>
    </SafeAreaView>
  );
}

/* =========================
   Reusable Section Card
========================= */
function SectionCard({
  icon,
  title,
  subtitle,
  rows,
  headerVariant = "green",
  topLeftAvatar,
}) {
  return (
    <View style={styles.card}>
      {/* Header */}
      <View
        style={[
          styles.sectionHeader,
          headerVariant === "green" && styles.sectionHeaderGreen,
        ]}
      >
        <Text style={styles.sectionHeaderIcon}>{icon}</Text>

        <View style={{ flex: 1 }}>
          <Text style={styles.sectionHeaderTitle}>
            {title} <Text style={styles.sectionHeaderSub}>{subtitle}</Text>
          </Text>
        </View>
      </View>

      {/* Optional avatar row (no real image) */}
      {topLeftAvatar ? (
        <View style={styles.avatarRow}>
          <View style={styles.avatarCircle}>
            <Text style={styles.avatarText}>{topLeftAvatar.initials}</Text>
          </View>
          <Text style={styles.avatarName}>{topLeftAvatar.name}</Text>
        </View>
      ) : null}

      {/* Rows */}
      {rows.map((r, idx) => (
        <View
          key={`${r.label}-${idx}`}
          style={[
            styles.row,
            idx === rows.length - 1 ? styles.rowLast : null,
          ]}
        >
          <Text style={styles.rowIcon}>{r.icon}</Text>

          <Text style={styles.rowLabel}>
            {r.label}
            <Text style={styles.colon}> :</Text>
          </Text>

          {r.isStatus ? (
            <View style={styles.statusChip}>
              <Text style={styles.statusChipText}>{r.value}</Text>
            </View>
          ) : (
            <Text style={styles.rowValue}>{r.value}</Text>
          )}
        </View>
      ))}
    </View>
  );
}

